+    int flags = MAP_ANONYMOUS | MAP_PRIVATE | MAP_FIXED | MAP_NORESERVE;
+    void* h = mmap(vaddr, length, prot, flags, -1, 0);
+    logv("do_map_allocate: mmap(%p, %zu, %d, %d, -1, 0) returns: %p", vaddr, length, prot, flags, h);
+    if (h == (void*) -1) {
