+void warn(const char* format, ...) {
+    char buffer[BUFLEN];
+    memset(buffer, 0, BUFLEN);
+    va_list args;
+    va_start(args, format);
+    vsnprintf(buffer, BUFLEN - 1, format, args);
+    va_end(args);
+    write0(2 /* stderr */, buffer);
+    write0(2, "\n");
+}
+
+void error(const char* format, ...) {
+    char buffer[BUFLEN];
+    memset(buffer, 0, BUFLEN);
+    va_list args;
+    va_start(args, format);
+    vsnprintf(buffer, BUFLEN - 1, format, args);
+    va_end(args);
+    write0(2 /* stderr */, buffer);
+    write0(2, "\n");
