+void conflict_check(void* vaddr, size_t length) {
+     const char* msg = conflict_check_pd(vaddr, length);
+     if (msg != nullptr) {
+         warn("revival: conflict: 0x%lx - 0x%lx len=%zx: %s", (uint64_t) vaddr, ((uint64_t) vaddr + length), length, msg);
+         exitForRetry();
+     }
