+/**
+ * Resolve a symbol from jvm.symbols, and call it.
+ * Use the symbol() function which will try using jvm.symbols first, then a live lookup.
+ */
+void* symbol_call(const char* sym) {
+    void* p = symbol(sym);
+    if (p == (void*) -1) {
+        return (void*) -1;
+    }
+    logv("symbol call: %p", p);
+    void* (*func)() = (void*(*)()) p;
+    return (func)();
+}
