+bool can_lazycopy_pd(void* addr) {
+    MEMORY_BASIC_INFORMATION meminfo;
+    size_t q = VirtualQueryEx(hProc, addr, &meminfo, sizeof(meminfo));
+    if (q != sizeof(meminfo)) {
+        warn("VirtualQueryEx failed");
+        return false;
+    }
+    if ((meminfo.Protect & PAGE_GUARD) != 0) {
+        return true;
+    } else {
+        return false;
+    }
+}
